import type {
  FormatOptions,
  ConvertibleUnit,
  Unit,
} from '@dynatrace-sdk/units';

/**
 * Type guard to ensure we are working with the FormatterOptions.
 *
 * @param formatter - given formatter fn or options
 * @internal
 */
export function isFormatterOptions(
  formatter: AnyNumericFormatter | undefined,
): formatter is FormatOptions<Unit, ConvertibleUnit> {
  return typeof formatter === 'object';
}

/** @public */
export type Formatter = (value: number, unit?: string | Unit) => string;

/** @public */
export type CategoricalFormatter = (
  value: string,
  data: Record<string, unknown>,
) => string;

/**
 * @internal
 */
export type AnyNumericFormatter =
  | Formatter
  | FormatOptions<Unit, ConvertibleUnit>;

/** @internal */
export type FormatterWithPrecision = (
  value: number,
  unit?: string | Unit,
  precision?: number,
) => string;

/**
 * @internal
 */
export type DateTimeFormatter = (input: number | Date) => string;

/**
 * @internal
 */
export type TimeFrameFormatter = (from: Date, to?: Date) => string;

/**
 * Pre-bound categorical formatter used inside chart utilities. The original
 * `CategoricalFormatter` is wrapped once with its associated datum so that
 * downstream code only deals with a `(value) => string` shape, matching the
 * other formatter types.
 *
 * @internal
 */
export type StringFormatter = (value: string) => string;

/**
 * Custom formatter for Dates
 * @public
 */
export type TimeFormatter = (time: Date) => string;

/**
 * @internal
 */
export function isUnit(unit: string | Unit): unit is Unit {
  return typeof unit === 'object';
}
